import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.BYYsWsaA.js";const u=JSON.parse('{"title":"Writing a Document","description":"","frontmatter":{},"headers":[],"relativePath":"docs-editor/writing-a-document.md","filePath":"docs-editor/writing-a-document.md"}'),n={name:"docs-editor/writing-a-document.md"};function l(i,t,s,d,h,c){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="writing-a-document" tabindex="-1">Writing a Document <a class="header-anchor" href="#writing-a-document" aria-label="Permalink to &quot;Writing a Document&quot;">​</a></h1><p>This guide covers creating and editing documents in Wafflebase — a word-processor-style editor with real-time collaboration.</p><h2 id="create-a-document" tabindex="-1">Create a Document <a class="header-anchor" href="#create-a-document" aria-label="Permalink to &quot;Create a Document&quot;">​</a></h2><ol><li>Open your workspace</li><li>Click the <strong>New</strong> dropdown button</li><li>Select <strong>New Document</strong></li></ol><p>A blank document opens with a page-style layout, similar to Google Docs.</p><h2 id="basic-editing" tabindex="-1">Basic Editing <a class="header-anchor" href="#basic-editing" aria-label="Permalink to &quot;Basic Editing&quot;">​</a></h2><p>Click anywhere on the page to place your cursor and start typing. The editor works like a standard word processor:</p><ul><li><strong>Enter</strong> — Split into a new paragraph</li><li><strong>Backspace / Delete</strong> — Remove characters</li><li><strong>Arrow keys</strong> — Move the cursor</li><li>Text wraps automatically at the page edge</li></ul><h3 id="select-text" tabindex="-1">Select Text <a class="header-anchor" href="#select-text" aria-label="Permalink to &quot;Select Text&quot;">​</a></h3><ul><li><strong>Click and drag</strong> to select a range of text</li><li><strong>Double-click</strong> to select a word</li><li><strong>Triple-click</strong> to select a paragraph</li><li><strong>⌘+A</strong> / <strong>Ctrl+A</strong> to select all text</li></ul><h3 id="copy-cut-and-paste" tabindex="-1">Copy, Cut, and Paste <a class="header-anchor" href="#copy-cut-and-paste" aria-label="Permalink to &quot;Copy, Cut, and Paste&quot;">​</a></h3><ul><li><strong>⌘+C</strong> / <strong>Ctrl+C</strong> — Copy selected text</li><li><strong>⌘+X</strong> / <strong>Ctrl+X</strong> — Cut selected text</li><li><strong>⌘+V</strong> / <strong>Ctrl+V</strong> — Paste text</li></ul><p>When pasting multi-line text, each line becomes a separate paragraph.</p><h2 id="text-formatting" tabindex="-1">Text Formatting <a class="header-anchor" href="#text-formatting" aria-label="Permalink to &quot;Text Formatting&quot;">​</a></h2><p>Use the formatting toolbar at the top or keyboard shortcuts to style your text.</p><h3 id="inline-styles" tabindex="-1">Inline Styles <a class="header-anchor" href="#inline-styles" aria-label="Permalink to &quot;Inline Styles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Style</th><th>Toolbar</th><th>Shortcut</th></tr></thead><tbody><tr><td><strong>Bold</strong></td><td><strong>B</strong> button</td><td>⌘+B / Ctrl+B</td></tr><tr><td><em>Italic</em></td><td><em>I</em> button</td><td>⌘+I / Ctrl+I</td></tr><tr><td><u>Underline</u></td><td>U button</td><td>⌘+U / Ctrl+U</td></tr><tr><td><s>Strikethrough</s></td><td>S button</td><td>⌘+Shift+X / Ctrl+Shift+X</td></tr><tr><td>Text color</td><td>A button</td><td>Pick from the color palette</td></tr></tbody></table><p>To clear all formatting from selected text, press <strong>⌘+\\</strong> / <strong>Ctrl+\\</strong>.</p><h3 id="paragraph-alignment" tabindex="-1">Paragraph Alignment <a class="header-anchor" href="#paragraph-alignment" aria-label="Permalink to &quot;Paragraph Alignment&quot;">​</a></h3><p>Use the alignment dropdown in the toolbar to align paragraphs:</p><ul><li><strong>Left</strong> — Default alignment</li><li><strong>Center</strong> — Centered text</li><li><strong>Right</strong> — Right-aligned text</li></ul><h2 id="tables" tabindex="-1">Tables <a class="header-anchor" href="#tables" aria-label="Permalink to &quot;Tables&quot;">​</a></h2><p>Insert a table from the toolbar to lay out structured content. Click the <strong>Table</strong> button, drag to pick the grid size, and the table appears at the cursor.</p><ul><li><strong>Tab</strong> moves between cells (Shift+Tab moves backward).</li><li>Right-click a cell for row and column operations — insert above/below, insert left/right, delete row/column, merge or split cells.</li><li>Drag a column or row border to resize.</li><li>Tables can be nested — insert a table inside a cell to build sub-grids.</li></ul><p>When a table is taller than the remaining space on a page, its rows split across the page boundary automatically.</p><h2 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to &quot;Images&quot;">​</a></h2><p>Click the <strong>Insert image</strong> button in the toolbar and choose:</p><ul><li><strong>Upload from computer</strong> — pick an image file from your device.</li><li><strong>By URL…</strong> — paste the address of an image on the web.</li></ul><p>You can also drag an image file straight onto the page, or paste one copied from another app.</p><p>Once an image is placed, click it to select it. Eight square handles appear around the edges:</p><ul><li>Drag a <strong>corner</strong> handle to resize while keeping the aspect ratio (hold <strong>Shift</strong> to resize freely).</li><li>Drag a <strong>side</strong> handle to stretch one dimension.</li><li><strong>Arrow keys</strong> nudge the image a pixel at a time (<strong>Shift</strong> for larger steps).</li><li><strong>Delete</strong> / <strong>Backspace</strong> removes it; <strong>Esc</strong> deselects.</li></ul><h2 id="pagination" tabindex="-1">Pagination <a class="header-anchor" href="#pagination" aria-label="Permalink to &quot;Pagination&quot;">​</a></h2><p>Documents use a page-based layout similar to a printed document. Pages default to A4 with standard margins, and text flows across pages as you type.</p><ul><li>Long paragraphs and tables break naturally at the page boundary — line splitting keeps headings, table headers, and partial rows in sync with the layout.</li><li>The editor renders one page per &quot;sheet&quot; so you can scroll through the deck of pages exactly as they will print or export.</li><li>Export to PDF preserves the same pagination — what you see on screen matches the exported document.</li></ul><h2 id="headers-footers" tabindex="-1">Headers &amp; Footers <a class="header-anchor" href="#headers-footers" aria-label="Permalink to &quot;Headers &amp; Footers&quot;">​</a></h2><p>Add content that repeats on every page — a title, a date, or a page number.</p><ul><li><strong>Double-click</strong> the margin area above the body (header) or below it (footer) to start editing it. Click back into the body, or press <strong>Esc</strong>, to leave.</li><li>While editing a header or footer, click <strong>Insert page number</strong> in the toolbar to drop in a number that updates automatically on each page.</li></ul><p>A header or footer applies to the whole document. Tables, page breaks, and horizontal rules can&#39;t be placed inside them.</p><h2 id="spell-check" tabindex="-1">Spell Check <a class="header-anchor" href="#spell-check" aria-label="Permalink to &quot;Spell Check&quot;">​</a></h2><p>Misspelled words are underlined with a red squiggle as you type — spell check is on by default. Right-click an underlined word to see suggestions and click one to replace it.</p><p>Spell check currently covers English (Latin-script) words in the body text.</p><h2 id="undo-and-redo" tabindex="-1">Undo and Redo <a class="header-anchor" href="#undo-and-redo" aria-label="Permalink to &quot;Undo and Redo&quot;">​</a></h2><ul><li><strong>⌘+Z</strong> / <strong>Ctrl+Z</strong> — Undo the last action</li><li><strong>⌘+Shift+Z</strong> / <strong>Ctrl+Y</strong> — Redo</li></ul><p>You can also use the undo/redo buttons in the toolbar.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><ul><li><a href="./keyboard-shortcuts.html">Keyboard Shortcuts</a> — Full list of document editor shortcuts</li><li><a href="/docs/guide/collaboration.html">Collaboration &amp; Sharing</a> — Share and edit documents together in real time</li></ul>',46)])])}const p=e(n,[["render",l]]);export{u as __pageData,p as default};
